package ru.lifegame.assets.domain.model.asset;

import java.util.List;

/**
 * Schema definition for sprite-atlas.json v2.0 — the versioned atlas configuration
 * generated by the asset pipeline and consumed by the frontend SpriteController.
 * <p>
 * <b>Config Version: 2.0</b>
 * <p>
 * Conditions are expressed as predicate arrays over typed spaces:
 * <pre>
 * {
 *   "configVersion": "2.0",
 *   "revision": "latest",
 *   "entity": "tanya",
 *   "displayScale": 3.0,
 *   "animations": {
 *     "idle": {
 *       "file": "idle_atlas.png",
 *       "layout": "grid",
 *       "renderMode": "sprite",
 *       "columns": 8,
 *       "frameWidth": 96,
 *       "frameHeight": 185,
 *       "rows": [
 *         {
 *           "rowIndex": 0,
 *           "condition": {
 *             "all": [
 *               { "space": "player", "stat": "energy", "operator": ">=", "value": 60 }
 *             ]
 *           },
 *           "fps": 8,
 *           "loop": true
 *         },
 *         {
 *           "rowIndex": 1,
 *           "condition": { "all": [] },
 *           "fps": 4,
 *           "loop": true
 *         }
 *       ],
 *       "defaultRow": 1
 *     },
 *     "window_overlay": {
 *       "file": "window_overlay_atlas.png",
 *       "layout": "grid",
 *       "renderMode": "overlay",
 *       "columns": 1,
 *       "frameWidth": 128,
 *       "frameHeight": 192,
 *       "rows": [
 *         {
 *           "rowIndex": 0,
 *           "condition": {
 *             "all": [
 *               { "space": "context", "stat": "time", "operator": ">=", "value": "06:00" },
 *               { "space": "context", "stat": "time", "operator": "<", "value": "18:00" }
 *             ]
 *           },
 *           "tint": "#FFFFFF",
 *           "opacity": 1.0,
 *           "fps": 1,
 *           "loop": false
 *         }
 *       ],
 *       "defaultRow": 0
 *     }
 *   }
 * }
 * </pre>
 */
public record AtlasConfigSchema(
        String configVersion,
        String revision,
        String entity,
        double displayScale,
        java.util.Map<String, AnimationEntry> animations
) {
    public static final String CURRENT_VERSION = "2.0";
    public static final String LATEST_REVISION = "latest";
    public static final double DEFAULT_DISPLAY_SCALE = 1.0;

    /**
     * A single predicate in a condition array.
     *
     * @param space    predicate space: "context", "player", "npc", "world", "inventory",
     *                 "action_history", "relationship"
     * @param npcId   required when space is "npc" or "relationship"; null otherwise
     * @param stat     stat name within the space (e.g. "energy", "time", "affection")
     * @param operator comparison operator: ">", "<", ">=", "<=", "==", "!=", "has"
     * @param value    comparison value; Number serialised without quotes, String with quotes
     */
    public record SingleCondition(
            String space,
            String npcId,
            String stat,
            String operator,
            Object value
    ) {}

    /**
     * Condition block: { "all": [...] }.
     * An empty list means always-true (default row).
     */
    public record RowCondition(
            List<SingleCondition> all
    ) {}

    /**
     * Single animation entry within the config.
     *
     * @param file        atlas PNG filename (relative to animations/ dir)
     * @param layout      always "grid"
     * @param renderMode  "sprite" (default) or "overlay"
     * @param cropOffset  if frames were cropped, the offset within original canvas
     * @param columns     number of frame columns in the atlas
     * @param frameWidth  width of one animation frame in pixels (cropped if applicable)
     * @param frameHeight height of one animation frame in pixels (cropped if applicable)
     * @param rows        row definitions (one per variant; single row for default animations)
     * @param defaultRow  default row index
     */
    public record AnimationEntry(
            String file,
            String layout,
            String renderMode,
            CropOffset cropOffset,
            int columns,
            int frameWidth,
            int frameHeight,
            List<RowDef> rows,
            int defaultRow
    ) {}

    /**
     * Crop offset info — present when animation frames were cropped to their
     * non-transparent bounding box during generation.
     *
     * @param x              X offset of cropped region from original canvas top-left
     * @param y              Y offset of cropped region from original canvas top-left
     * @param originalWidth  full uncropped canvas width
     * @param originalHeight full uncropped canvas height
     */
    public record CropOffset(
            int x,
            int y,
            int originalWidth,
            int originalHeight
    ) {}

    /**
     * Row definition for grid layouts.
     */
    public record RowDef(
            int rowIndex,
            RowCondition condition,
            String tint,
            Double opacity,
            int fps,
            boolean loop
    ) {
        public RowDef(int rowIndex, RowCondition condition, int fps, boolean loop) {
            this(rowIndex, condition, null, null, fps, loop);
        }
    }
}
